4	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
5	pub enum Backend {
6	    /// Tart VMs (macOS Apple Silicon). Detected, not yet driven by ezgha.
7	    Tart,
8	    /// libvirt/KVM VMs (Linux). Detected, not yet driven by ezgha.
9	    Libvirt,
10	    /// Docker with the sysbox-runc runtime (stronger container isolation).
11	    DockerSysbox,
12	    /// Plain Docker with hard resource limits.
13	    Docker,
14	}
15	
16	impl Backend {
17	    pub fn isolation(self) -> IsolationLevel {
18	        match self {
19	            Backend::Tart | Backend::Libvirt => IsolationLevel::Vm,
20	            Backend::DockerSysbox | Backend::Docker => IsolationLevel::Container,
21	        }
22	    }
23	
24	    /// Whether ezgha can actually start runners on this backend today.
25	    /// Tart/libvirt are detected and reported by `doctor`, but driving them
26	    /// (image management, cloud-init, VM lifecycle) is milestone 2.
27	    pub fn implemented(self) -> bool {
28	        matches!(self, Backend::DockerSysbox | Backend::Docker)
29	    }
30	
31	    pub fn name(self) -> &'static str {
32	        match self {
33	            Backend::Tart => "tart (VM)",
34	            Backend::Libvirt => "libvirt (VM)",
35	            Backend::DockerSysbox => "docker+sysbox (container)",
36	            Backend::Docker => "docker (container)",
37	        }
38	    }
39	}
40	
41	/// Every backend this host could offer, strongest isolation first.
42	pub fn candidates(plat: &Platform) -> Vec<Backend> {
43	    let mut out = Vec::new();
44	    if plat.os == "macos" && plat.has_tart {
45	        out.push(Backend::Tart);
46	    }
47	    if plat.os == "linux" && plat.kvm_usable && plat.has_virsh {
48	        out.push(Backend::Libvirt);
49	    }
50	    if plat.docker_ok && plat.sysbox_runtime {
51	        out.push(Backend::DockerSysbox);
52	    }
53	    if plat.docker_ok {
54	        out.push(Backend::Docker);
55	    }
56	    out
57	}
58	
59	pub enum Selection {
60	    /// Best implemented backend, plus any stronger-but-unimplemented ones we
61	    /// skipped (so callers can warn instead of silently degrading).
62	    Chosen {
63	        backend: Backend,
64	        skipped_stronger: Vec<Backend>,
65	    },
66	    /// Host has a usable backend but policy demands stronger isolation.
67	    PolicyBlocked {
68	        best_available: Backend,
69	        required: IsolationLevel,
70	    },
71	    /// Nothing usable at all.
72	    None,
73	}
74	
75	pub fn select(plat: &Platform, minimum: IsolationLevel) -> Selection {
76	    let cands = candidates(plat);
77	    let mut skipped = Vec::new();
78	    for backend in &cands {
79	        if !backend.implemented() {
80	            skipped.push(*backend);
81	            continue;
82	        }
83	        if backend.isolation() < minimum {
84	            return Selection::PolicyBlocked {
85	                best_available: *backend,
86	                required: minimum,
87	            };
88	        }
89	        return Selection::Chosen {
90	            backend: *backend,
91	            skipped_stronger: skipped,
92	        };
93	    }
94	    Selection::None
95	}
