4	/// What this host can offer, detected at runtime.
5	#[derive(Debug, Clone)]
6	pub struct Platform {
7	    pub os: &'static str,
8	    pub arch: &'static str,
9	    /// /dev/kvm exists AND this user can open it read-write.
10	    pub kvm_usable: bool,
11	    pub has_tart: bool,
12	    pub has_virsh: bool,
13	    /// Docker CLI present and the daemon answered.
14	    pub docker_ok: bool,
15	    /// sysbox-runc registered as a Docker runtime.
16	    pub sysbox_runtime: bool,
17	    pub total_mem_mb: u64,
18	    pub cpus: u32,
19	}
20	
21	pub fn detect() -> Platform {
22	    let os = if cfg!(target_os = "macos") {
23	        "macos"
24	    } else if cfg!(target_os = "linux") {
25	        "linux"
26	    } else {
27	        "unsupported"
28	    };
29	
30	    Platform {
31	        os,
32	        arch: std::env::consts::ARCH,
33	        kvm_usable: kvm_usable(),
34	        has_tart: which::which("tart").is_ok(),
35	        has_virsh: which::which("virsh").is_ok(),
36	        docker_ok: docker_daemon_ok(),
37	        sysbox_runtime: sysbox_runtime_present(),
38	        total_mem_mb: total_mem_mb(),
39	        cpus: std::thread::available_parallelism()
40	            .map(|n| n.get() as u32)
41	            .unwrap_or(1),
42	    }
43	}
44	
45	/// Existence alone is not enough: the user must be in the kvm group (or have
46	/// an ACL) for the device to be usable, so try to actually open it.
47	fn kvm_usable() -> bool {
48	    OpenOptions::new()
49	        .read(true)
50	        .write(true)
51	        .open("/dev/kvm")
52	        .is_ok()
53	}
54	
55	fn docker_daemon_ok() -> bool {
56	    Command::new("docker")
57	        .args(["version", "--format", "{{.Server.Version}}"])
58	        .output()
59	        .map(|o| o.status.success())
60	        .unwrap_or(false)
61	}
62	
63	fn sysbox_runtime_present() -> bool {
64	    Command::new("docker")
65	        .args(["info", "--format", "{{json .Runtimes}}"])
66	        .output()
67	        .map(|o| o.status.success() && String::from_utf8_lossy(&o.stdout).contains("sysbox-runc"))
68	        .unwrap_or(false)
69	}
70	
71	fn total_mem_mb() -> u64 {
72	    #[cfg(target_os = "linux")]
73	    {
74	        if let Ok(meminfo) = std::fs::read_to_string("/proc/meminfo") {
75	            for line in meminfo.lines() {
76	                if let Some(rest) = line.strip_prefix("MemTotal:") {
77	                    let kb: u64 = rest
78	                        .trim()
79	                        .trim_end_matches(" kB")
80	                        .trim()
81	                        .parse()
82	                        .unwrap_or(0);
83	                    return kb / 1024;
84	                }
85	            }
86	        }
87	        0
88	    }
89	    #[cfg(target_os = "macos")]
90	    {
91	        Command::new("sysctl")
92	            .args(["-n", "hw.memsize"])
93	            .output()
94	            .ok()
95	            .and_then(|o| {
96	                String::from_utf8_lossy(&o.stdout)
97	                    .trim()
98	                    .parse::<u64>()
99	                    .ok()
100	            })
101	            .map(|b| b / 1024 / 1024)
102	            .unwrap_or(0)
103	    }
104	    #[cfg(not(any(target_os = "linux", target_os = "macos")))]
105	    {
106	        0
107	    }
108	}
