5	/// Install a user-level service that runs `ezgha serve` at login and keeps
6	/// it running: systemd --user on Linux, launchd on macOS.
7	pub fn install() -> Result<()> {
8	    let exe = std::env::current_exe().context("cannot resolve ezgha binary path")?;
9	    if cfg!(target_os = "linux") {
10	        install_systemd(&exe)
11	    } else if cfg!(target_os = "macos") {
12	        install_launchd(&exe)
13	    } else {
14	        bail!("service install is only supported on linux (systemd --user) and macos (launchd)")
15	    }
16	}
17	
18	fn home() -> Result<PathBuf> {
19	    std::env::var_os("HOME")
20	        .map(PathBuf::from)
21	        .context("HOME not set")
22	}
23	
24	fn install_systemd(exe: &std::path::Path) -> Result<()> {
25	    let unit_dir = home()?.join(".config/systemd/user");
26	    std::fs::create_dir_all(&unit_dir)?;
27	    let unit_path = unit_dir.join("ezgha.service");
28	    let unit = format!(
29	        "[Unit]\n\
30	         Description=ez-gh-actions ephemeral GitHub Actions runners\n\
31	         After=network-online.target docker.service\n\n\
32	         [Service]\n\
33	         ExecStart={} serve\n\
34	         Restart=on-failure\n\
35	         RestartSec=10\n\n\
36	         [Install]\n\
37	         WantedBy=default.target\n",
38	        exe.display()
39	    );
40	    std::fs::write(&unit_path, unit)?;
41	    println!("wrote {}", unit_path.display());
42	
43	    for args in [
44	        vec!["--user", "daemon-reload"],
45	        vec!["--user", "enable", "--now", "ezgha.service"],
46	    ] {
47	        let out = Command::new("systemctl").args(&args).output()?;
48	        if !out.status.success() {
49	            bail!(
50	                "systemctl {:?} failed: {}",
51	                args,
52	                String::from_utf8_lossy(&out.stderr)
53	            );
54	        }
55	    }
56	    println!("service enabled: systemctl --user status ezgha.service");
57	    Ok(())
58	}
59	
60	fn install_launchd(exe: &std::path::Path) -> Result<()> {
61	    let agents = home()?.join("Library/LaunchAgents");
62	    std::fs::create_dir_all(&agents)?;
63	    let plist_path = agents.join("org.jleechanorg.ezgha.plist");
64	    let plist = format!(
65	        r#"<?xml version="1.0" encoding="UTF-8"?>
66	<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
67	<plist version="1.0">
68	<dict>
69	    <key>Label</key><string>org.jleechanorg.ezgha</string>
70	    <key>ProgramArguments</key>
